190→const assertActiveWeek = async(weekId) => {
191→    const {data: week, error: weekError} = await supabase
192→        .from("freedom_wall_weeks")
193→        .select("id, week_start, week_end, status")
194→        .eq("id", weekId)
195→        .maybeSingle();
196→
197→    if(weekError){
198→        console.error("supabase error while reading freedom wall week:", weekError.message);
199→        throw {status: 500, error: "failed to read freedom wall week"};
200→    }
201→
202→    if(!week?.id){
203→        throw {status: 404, error: "freedom wall week not found"};
204→    }
205→
206→    const nowIso = new Date().toISOString();
207→    if(week.status !== "active" || nowIso < week.week_start || nowIso >= week.week_end){
208→        throw {status: 409, error: "freedom wall week is not active"};
209→    }
210→
211→    return week;
212→};
