227→export const getCurrentFreedomWallWeekService = async() => {
228→    let {data: activeWeek, error: activeWeekError} = await supabase
229→        .from("freedom_wall_weeks")
230→        .select("*")
231→        .eq("status", "active")
232→        .order("week_start", {ascending: false})
233→        .limit(1)
234→        .maybeSingle();
235→
236→    if(activeWeekError){
237→        console.error("supabase error while reading active freedom wall week:", activeWeekError.message);
238→        throw {status: 500, error: "failed to fetch active freedom wall week"};
239→    }
240→
241→    if(!activeWeek){
242→        const {error: rotateError} = await supabase.rpc("rotate_freedom_wall_week");
243→        if(rotateError){
244→            console.error("rotate_freedom_wall_week rpc error:", rotateError.message);
245→        }
246→
247→        const retry = await supabase
248→            .from("freedom_wall_weeks")
249→            .select("*")
250→            .eq("status", "active")
251→            .order("week_start", {ascending: false})
252→            .limit(1)
253→            .maybeSingle();
254→
255→        activeWeek = retry.data;
256→        activeWeekError = retry.error;
257→    }
258→
259→    if(activeWeekError){
260→        console.error("supabase error while reading active freedom wall week:", activeWeekError.message);
261→        throw {status: 500, error: "failed to fetch active freedom wall week"};
262→    }
263→
264→    if(!activeWeek){
265→        throw {status: 404, error: "no active freedom wall week found"};
266→    }
267→
268→    return {week: activeWeek};
269→};
