271→export const getFreedomWallItemsService = async(weekId, limit, cursor, types) => {
272→    if(!weekId){
273→        throw {status: 400, error: "weekId is required"};
274→    }
275→
276→    const parsedLimit = parseLimit(limit);
277→    const typeFilters = parseTypeFilters(types);
278→
279→    let query = supabase
280→        .from("freedom_wall_items")
281→        .select(selectItemColumns)
282→        .eq("week_id", weekId)
283→        .is("deleted_at", null)
284→        .order("z_index", {ascending: true})
285→        .order("created_at", {ascending: true})
286→        .order("id", {ascending: true})
287→        .limit(parsedLimit + 1);
288→
289→    if(cursor){
290→        query = query.gt("created_at", cursor);
291→    }
292→
293→    if(typeFilters.length > 0){
294→        query = query.in("item_type", typeFilters);
295→    }
296→
297→    const {data: items, error: itemsError} = await query;
298→
299→    if(itemsError){
300→        console.error("supabase error while reading freedom wall items:", itemsError.message);
301→        throw {status: 500, error: "failed to fetch freedom wall items"};
302→    }
303→
304→    const hasMore = (items || []).length > parsedLimit;
305→    const slicedItems = hasMore ? items.slice(0, parsedLimit) : (items || []);
306→    const nextCursor = hasMore
307→        ? slicedItems[slicedItems.length - 1]?.created_at || null
308→        : null;
309→
310→    return {
311→        data: slicedItems,
312→        hasMore: hasMore,
313→        nextCursor: nextCursor
314→    };
315→};
