317→export const createFreedomWallItemService = async({weekId, itemType, payload, zIndex = 0, userId}) => {
318→    if(!userId){
319→        throw {status: 401, error: "not authorized"};
320→    }
321→
322→    if(!weekId){
323→        throw {status: 400, error: "weekId is required"};
324→    }
325→
326→    const normalizedType = typeof itemType === "string" ? itemType.trim().toLowerCase() : "";
327→    if(!FREEDOM_WALL_ITEM_TYPES.includes(normalizedType)){
328→        throw {status: 400, error: "invalid freedom wall item type"};
329→    }
330→
331→    await assertActiveWeek(weekId);
332→
333→    const sanitizedPayload = sanitizePayloadByType(normalizedType, payload);
334→    const parsedZIndex = clamp(normalizeNumber(zIndex, 0), -100000, 100000);
335→
336→    const {data: createdItem, error: createError} = await supabase
337→        .from("freedom_wall_items")
338→        .insert({
339→            week_id: weekId,
340→            user_id: userId,
341→            item_type: normalizedType,
342→            payload: sanitizedPayload,
343→            z_index: parsedZIndex
344→        })
345→        .select(selectItemColumns)
346→        .single();
347→
348→    if(createError){
349→        console.error("supabase error while creating freedom wall item:", createError.message);
350→        throwMappedDatabaseError(createError, "failed to create freedom wall item");
351→    }
352→
353→    return {item: createdItem};
354→};
