356→export const updateFreedomWallItemService = async({itemId, payload, zIndex, userId}) => {
357→    if(!userId){
358→        throw {status: 401, error: "not authorized"};
359→    }
360→
361→    if(!itemId){
362→        throw {status: 400, error: "itemId is required"};
363→    }
364→
365→    if(payload === undefined && zIndex === undefined){
366→        throw {status: 400, error: "payload or zIndex is required"};
367→    }
368→
369→    const {data: existingItem, error: existingItemError} = await supabase
370→        .from("freedom_wall_items")
371→        .select("id, week_id, user_id, item_type, payload, z_index")
372→        .eq("id", itemId)
373→        .is("deleted_at", null)
374→        .maybeSingle();
375→
376→    if(existingItemError){
377→        console.error("supabase error while reading freedom wall item:", existingItemError.message);
378→        throw {status: 500, error: "failed to read freedom wall item"};
379→    }
380→
381→    if(!existingItem?.id){
382→        throw {status: 404, error: "freedom wall item not found"};
383→    }
384→
385→    if(String(existingItem.user_id) !== String(userId)){
386→        throw {status: 403, error: "not allowed to edit this freedom wall item"};
387→    }
388→
389→    await assertActiveWeek(existingItem.week_id);
390→
391→    const updatePayload = {};
392→    if(payload !== undefined){
393→        const mergedPayload = {
394→            ...(existingItem.payload || {}),
395→            ...(payload || {})
396→        };
397→        updatePayload.payload = sanitizePayloadByType(existingItem.item_type, mergedPayload);
398→    }
399→
400→    if(zIndex !== undefined){
401→        updatePayload.z_index = clamp(normalizeNumber(zIndex, existingItem.z_index || 0), -100000, 100000);
402→    }
403→
404→    const {data: updatedItem, error: updateError} = await supabase
405→        .from("freedom_wall_items")
406→        .update(updatePayload)
407→        .eq("id", itemId)
408→        .select(selectItemColumns)
409→        .single();
410→
411→    if(updateError){
412→        console.error("supabase error while updating freedom wall item:", updateError.message);
413→        throwMappedDatabaseError(updateError, "failed to update freedom wall item");
414→    }
415→
416→    return {item: updatedItem};
417→};
